import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useParams } from 'react-router-dom';

export default function ViewAnswer() {
  const { attemptId } = useParams(); // route: /view-answer/:attemptId
  const [attempt, setAttempt] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAttempt = async () => {
      try {
        const res = await axios.get(`http://localhost:3000/api/examattempt/${attemptId}`);
        setAttempt(res.data);
        setLoading(false);
      } catch (err) {
        console.error(err);
        setLoading(false);
      }
    };

    fetchAttempt();
  }, [attemptId]);

  if (loading) return <div className="mt-4 text-center">Loading...</div>;

  if (!attempt) return <div className="mt-4 text-center text-red-500">Attempt not found.</div>;

  return (
    <div className="max-w-4xl p-4 mx-auto">
      <h2 className="mb-4 text-2xl font-semibold">View Your Answers</h2>
      {attempt.questions.map((question, idx) => (
        <div key={idx} className="p-4 mb-3 border rounded shadow-md">
          <p className="font-medium">Q{idx + 1}: {question.text}</p>
          <div className="mt-2">
            {question.options.map((option, i) => (
              <div
                key={i}
                className={`p-2 rounded-md mt-1
                  ${option === attempt.answers[idx] ? 'bg-yellow-100' : ''}
                  ${option === attempt.correctAnswers[idx] ? 'border-green-500 border' : ''}
                `}
              >
                {String.fromCharCode(65 + i)}. {option}
              </div>
            ))}
          </div>
          <div className="mt-2 text-sm text-gray-600">
            Your Answer: <strong>{attempt.answers[idx]}</strong><br />
            Correct Answer: <strong>{attempt.correctAnswers[idx]}</strong>
          </div>
        </div>
      ))}
    </div>
  );
}
